import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { BookingService, Booking, BookingPayload } from '../../services/booking.service';
import { ResourceService, Resource } from '../../services/resource.service';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-booking-form',
  templateUrl: './booking-form.component.html',
})
export class BookingFormComponent implements OnInit {
  isEdit = false;
  bookingId: number | null = null;
  loading = true;
  saving = false;
  error = '';

  resources: Resource[] = [];
  estados = ['pendiente', 'confirmada', 'cancelada'];

  form: BookingPayload & { id?: number } = {
    resourceId: 0,
    fechaInicio: '',
    fechaFin: '',
    asistentes: 1,
    motivo: '',
    clienteNombre: '',
    estado: 'pendiente',
  };

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private bookingSvc: BookingService,
    private resourceSvc: ResourceService,
    public auth: AuthService
  ) {}

  ngOnInit(): void {
    this.bookingId = this.route.snapshot.params['id'] ? +this.route.snapshot.params['id'] : null;
    this.isEdit = !!this.bookingId;

    this.resourceSvc.getAll().subscribe({
      next: r => {
        this.resources = r;
        if (this.isEdit) {
          this.loadBooking();
        } else {
          this.loading = false;
        }
      },
      error: e => {
        this.error = e.message;
        this.loading = false;
      },
    });
  }

  private loadBooking(): void {
    this.bookingSvc.getOne(this.bookingId!).subscribe({
      next: b => {
        this.form = {
          resourceId: b.resource?.id ?? 0,
          fechaInicio: this.toDatetimeLocal(b.fechaInicio),
          fechaFin: this.toDatetimeLocal(b.fechaFin),
          asistentes: b.asistentes,
          motivo: b.motivo ?? '',
          clienteNombre: b.clienteNombre ?? '',
          estado: b.estado,
        };
        this.loading = false;
      },
      error: e => {
        this.error = e.message;
        this.loading = false;
      },
    });
  }

  submit(): void {
    if (!this.form.resourceId || !this.form.fechaInicio || !this.form.fechaFin) {
      this.error = 'Recurso, fecha de inicio y fecha de fin son obligatorios';
      return;
    }

    this.saving = true;
    this.error = '';

    const payload: BookingPayload = {
      ...this.form,
      fechaInicio: this.fromDatetimeLocal(this.form.fechaInicio),
      fechaFin: this.fromDatetimeLocal(this.form.fechaFin),
    };

    const obs = this.isEdit
      ? this.bookingSvc.update(this.bookingId!, payload)
      : this.bookingSvc.create(payload);

    obs.subscribe({
      next: () => this.router.navigate(['/app/bookings']),
      error: e => {
        this.error = e.message;
        this.saving = false;
      },
    });
  }

  private toDatetimeLocal(dateStr: string): string {
    if (!dateStr) return '';
    return dateStr.replace(' ', 'T').substring(0, 16);
  }

  private fromDatetimeLocal(val: string): string {
    return val.replace('T', ' ') + ':00';
  }
}
<div class="d-flex align-items-center gap-2 mb-4">
  <a routerLink="/app/bookings" class="btn btn-sm btn-outline-secondary">
    <i class="bi bi-arrow-left"></i>
  </a>
  <div>
    <h4 class="fw-bold mb-0">{{ isEdit ? 'Editar reserva' : 'Nueva reserva' }}</h4>
    <p class="text-muted mb-0 small">{{ isEdit ? 'Modifica los datos de la reserva' : 'Rellena el formulario para crear una reserva' }}</p>
  </div>
</div>

<div *ngIf="loading" class="text-center py-5">
  <div class="spinner-border text-primary" role="status"></div>
</div>

<div *ngIf="error" class="alert alert-danger">{{ error }}</div>

<form (ngSubmit)="submit()" *ngIf="!loading" class="sb-card p-4" style="max-width:640px">
  <div class="mb-3">
    <label class="form-label fw-semibold">Recurso <span class="text-danger">*</span></label>
    <select class="form-select" [(ngModel)]="form.resourceId" name="resourceId" required>
      <option value="0" disabled>-- Selecciona un recurso --</option>
      <option *ngFor="let r of resources" [value]="r.id">
        {{ r.nombre }} (Cap. {{ r.capacidad }} · {{ r.precioHora }}€/h)
      </option>
    </select>
  </div>

  <div class="row g-3 mb-3">
    <div class="col-sm-6">
      <label class="form-label fw-semibold">Fecha inicio <span class="text-danger">*</span></label>
      <input type="datetime-local" class="form-control"
             [(ngModel)]="form.fechaInicio" name="fechaInicio" required>
    </div>
    <div class="col-sm-6">
      <label class="form-label fw-semibold">Fecha fin <span class="text-danger">*</span></label>
      <input type="datetime-local" class="form-control"
             [(ngModel)]="form.fechaFin" name="fechaFin" required>
    </div>
  </div>

  <div class="mb-3">
    <label class="form-label fw-semibold">Número de asistentes</label>
    <input type="number" class="form-control" [(ngModel)]="form.asistentes" name="asistentes" min="1">
  </div>

  <div class="mb-3">
    <label class="form-label fw-semibold">Motivo / descripción</label>
    <textarea class="form-control" [(ngModel)]="form.motivo" name="motivo" rows="3"></textarea>
  </div>

  <div class="mb-3" *ngIf="auth.isAdmin">
    <label class="form-label fw-semibold">Nombre del cliente</label>
    <input type="text" class="form-control" [(ngModel)]="form.clienteNombre" name="clienteNombre">
  </div>

  <div class="mb-4" *ngIf="auth.isAdmin">
    <label class="form-label fw-semibold">Estado</label>
    <select class="form-select" [(ngModel)]="form.estado" name="estado">
      <option *ngFor="let e of estados" [value]="e">{{ e | titlecase }}</option>
    </select>
  </div>

  <div class="d-flex gap-2">
    <button type="submit" class="btn btn-primary" [disabled]="saving">
      <span *ngIf="saving" class="spinner-border spinner-border-sm me-2"></span>
      <i *ngIf="!saving" class="bi bi-check-lg me-1"></i>
      {{ isEdit ? 'Guardar cambios' : 'Crear reserva' }}
    </button>
    <a routerLink="/app/bookings" class="btn btn-outline-secondary">Cancelar</a>
  </div>
</form>
